const fs = require('fs');
const path = require('path');

/**
 * Fix te-form examples for compound irregular verbs
 * These verbs had incorrect examples generated by the script
 */

const fixedExamples = {
  '連れて来る': [
    {
      japanese: '友達をパーティーに連れて来てください。',
      kana: 'ともだちをパーティーにつれてきてください。',
      english: 'Please bring your friend to the party.',
      highlight: 'polite request with movement'
    },
    {
      japanese: '妹を連れて来ています。',
      kana: 'いもうとをつれてきています。',
      english: 'I am bringing my younger sister.',
      highlight: 'progressive with movement'
    }
  ],
  '持って来る': [
    {
      japanese: '明日、教科書を持って来てください。',
      kana: 'あした、きょうかしょをもってきてください。',
      english: 'Please bring your textbook tomorrow.',
      highlight: 'polite request with object'
    },
    {
      japanese: 'お弁当を持って来ています。',
      kana: 'おべんとうをもってきています。',
      english: 'I am bringing a lunch box.',
      highlight: 'progressive with object'
    }
  ],
  'する': [
    {
      japanese: '宿題をしてから、遊びます。',
      kana: 'しゅくだいをしてから、あそびます。',
      english: 'I will play after doing homework.',
      highlight: 'sequential actions'
    },
    {
      japanese: '運動をしてください。',
      kana: 'うんどうをしてください。',
      english: 'Please exercise.',
      highlight: 'polite request'
    }
  ]
};

function fixExamples() {
  console.log('🔧 Fixing irregular verb te-form examples...\n');

  const filePath = path.join(__dirname, '../public/seed-data/N5_verbs_dataset.json');
  const backupPath = filePath + '.backup-before-example-fix-' + Date.now();

  const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));

  // Backup
  fs.writeFileSync(backupPath, JSON.stringify(data, null, 2));
  console.log(`✅ Backup: ${path.basename(backupPath)}\n`);

  let fixed = 0;

  // Fix each problematic verb
  data.verbs = data.verbs.map(verb => {
    if (fixedExamples[verb.kanji]) {
      console.log(`✓ Fixing ${verb.kanji} examples`);
      verb.teFormExamples = fixedExamples[verb.kanji];
      fixed++;
    }
    return verb;
  });

  // Save
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2));

  console.log(`\n✅ Fixed ${fixed} verbs with correct te-form examples!`);
  console.log(`💾 Saved: ${filePath}`);
}

fixExamples();
